-- =====================================================================
CREATE OR REPLACE FUNCTION OFSERM.EXTERNAL_HEDGE_DATA_POPULATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_MITIGANTS(N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_GAAP_SKEY,N_ISSUE_SKEY,N_MITIGANT_SKEY,N_MITIGANT_TYPE_SKEY,N_ISSUER_SKEY,N_MATURITY_DATE_SKEY,N_ORIGINAL_MATURITY,N_ORIGINAL_MITIGANT_VALUE,N_REF_ENTITY_SKEY,N_RESIDUAL_MATURITY,N_RUN_SKEY,N_VOLATILITY_HAIRCUT,N_CAP_APPROACH_TYPE_SKEY,V_APPROACH_TYPE,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_STD_MITIGANT_TYPE_SKEY,N_RUN_PARAMETER_SETUP_SKEY,D_VALUE_DATE,F_AGREEMENT_FLAG,F_CONDITIONAL_GUARANTEE_FLAG,F_CVA_HEDGE,F_DIL_RISK_MITIGANT_FLAG,F_DIRECT_GUARANTEE_FLAG,F_ELIGIBILITY_FLAG,F_ELIG_MUTUAL_FUND_IND,F_ELIG_NON_MAIN_INDEX_IND,F_EQUITY_TRADED_FLAG,F_ILLIQUID_COLLATERAL,F_MAIN_INDEX_IND,F_RESTRUC_COV_IND,F_RE_SECURITIZED_FLAG,F_SECURITIZED_FLAG,F_SENIOR_COLL_FLAG,F_UNRATED_DEB_SEC_ELG_FLAG,N_BASIS_RISK_WEIGHT,N_CDS_INDEX_AVG_SPREAD,N_DEFAULTED_POSITION,N_HLDG_PERIOD_FOR_HAIRCUT,N_LGD_PERCENT,N_MIN_HOLDING_PERIOD,N_MITIGANT_MIN_COLL_LEVEL,N_MITIGANT_OVER_COLL_LEVEL,N_MITIGANT_VALUE,N_PD_PERCENT,N_POST_VOL_HC_COLL_VALUE,N_REMARGIN_FREQUENCY,N_REVAL_FREQUENCY,N_RISK_WEIGHT,N_RISK_WEIGHT_EL,N_VALUE_CHANGE_PERCENT,V_CCY_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),to_char(DIM_ISSUE.N_ISSUE_SKEY),to_char(DIM_MITIGANT.N_MITIGANT_SKEY),to_char(DIM_MITIGANT_TYPE.N_MITIGANT_TYPE_SKEY),to_char(DIM_PARTY.N_PARTY_SKEY),A_dim_dates_mat.n_date_skey,TRUNC(D_MATURITY_DATE-D_VALUE_DATE)/365,stg_mitigants.n_mitigant_value,DIM_CUST_PARTY.n_party_skey,DATEDIFF(STG_MITIGANTS.FIC_MIS_DATE,D_MATURITY_DATE)/365,'870',COALESCE(STG_MITIGANTS.n_volatility_haircut,0),to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE,to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_MITIGANT_TYPE_RECLASS.N_STD_MITIGANT_TYPE_SKEY),to_char(FSI_RUN_PARAMETER.N_RUN_PARAMETER_SETUP_SKEY),STG_MITIGANTS.D_VALUE_DATE,STG_MITIGANTS.F_AGREEMENT_FLAG,STG_MITIGANTS.F_CONDITIONAL_GUARANTEE_FLAG,STG_MITIGANTS.F_CVA_HEDGE,STG_MITIGANTS.F_DIL_RISK_MITIGANT_FLAG,STG_MITIGANTS.F_DIRECT_GUARANTEE_FLAG,STG_MITIGANTS.F_ELIGIBILITY_FLAG,STG_MITIGANTS.F_ELIG_MUTUAL_FUND_IND,STG_MITIGANTS.F_ELIG_NON_MAIN_INDEX_IND,STG_MITIGANTS.F_EQUITY_TRADED_FLAG,STG_MITIGANTS.F_ILLIQUID_COLLATERAL,STG_MITIGANTS.F_MAIN_INDEX_IND,STG_MITIGANTS.F_RESTRUC_COV_IND,STG_MITIGANTS.F_RE_SECURITIZED_FLAG,STG_MITIGANTS.F_SECURITIZED_FLAG,STG_MITIGANTS.F_SENIOR_COLL_FLAG,STG_MITIGANTS.F_UNRATED_DEBT_SEC_ELIG_FLAG,to_char(STG_MITIGANTS.N_BASIS_RISK_WEIGHT),to_char(STG_MITIGANTS.N_CDS_INDEX_AVG_SPREAD),to_char(STG_MITIGANTS.N_DEFAULTED_POSITION),to_char(STG_MITIGANTS.N_HLDG_PERIOD_FOR_HAIRCUT),to_char(STG_MITIGANTS.N_LGD_PERCENT),to_char(STG_MITIGANTS.N_MIN_HOLDING_PERIOD),to_char(STG_MITIGANTS.N_MITIGANT_MIN_COLL_LEVEL),to_char(STG_MITIGANTS.N_MITIGANT_OVER_COLL_LEVEL),to_char(STG_MITIGANTS.N_MITIGANT_VALUE),to_char(STG_MITIGANTS.N_PD_PERCENT),to_char(STG_MITIGANTS.N_POST_VOL_HC_COLL_VALUE),to_char(STG_MITIGANTS.N_REMARGIN_FREQUENCY),to_char(STG_MITIGANTS.N_REVAL_FREQUENCY),to_char(STG_MITIGANTS.N_RISK_WEIGHT),to_char(STG_MITIGANTS.N_RISK_WEIGHT_EL),to_char(STG_MITIGANTS.N_VALUE_CHANGE_PERCENT),STG_MITIGANTS.V_CCY_CODE FROM STG_MITIGANTS INNER JOIN DIM_DATES ON STG_MITIGANTS.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') LEFT OUTER JOIN DIM_MITIGANT_TYPE ON STG_MITIGANTS.V_MITIGANT_TYPE_CODE = DIM_MITIGANT_TYPE.V_MITIGANT_TYPE AND to_date('20260331','YYYYMMDD') BETWEEN COALESCE(DIM_MITIGANT_TYPE.D_RECORD_START_DATE, to_date('20260331','YYYYMMDD')) AND COALESCE(DIM_MITIGANT_TYPE.D_RECORD_END_DATE, to_date('20260331','YYYYMMDD')) LEFT OUTER JOIN DIM_GAAP ON STG_MITIGANTS.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') BETWEEN COALESCE(DIM_GAAP.D_RECORD_START_DATE, to_date('20260331','YYYYMMDD')) AND COALESCE(DIM_GAAP.D_RECORD_END_DATE, to_date('20260331','YYYYMMDD')) INNER JOIN DIM_MITIGANT ON STG_MITIGANTS.V_MITIGANT_CODE = DIM_MITIGANT.V_MITIGANT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN COALESCE(DIM_MITIGANT.D_RECORD_START_DATE, to_date('20260331','YYYYMMDD')) AND COALESCE(DIM_MITIGANT.D_RECORD_END_DATE, to_date('20260331','YYYYMMDD')) LEFT OUTER JOIN DIM_PARTY DIM_CUST_PARTY ON STG_MITIGANTS.V_REF_ENTITY_PARTY_ID = DIM_CUST_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN COALESCE(DIM_CUST_PARTY.D_RECORD_START_DATE, to_date('20260331','YYYYMMDD')) AND COALESCE(DIM_CUST_PARTY.D_RECORD_END_DATE, to_date('20260331','YYYYMMDD')) LEFT OUTER JOIN DIM_COUNTRY ON COALESCE(STG_MITIGANTS.V_COUNTRY_CODE, 'MSG') = DIM_COUNTRY.V_COUNTRY_ID AND to_date('20260331','YYYYMMDD') BETWEEN COALESCE(DIM_COUNTRY.D_RECORD_START_DATE, to_date('20260331','YYYYMMDD')) AND COALESCE(DIM_COUNTRY.D_RECORD_END_DATE, to_date('20260331','YYYYMMDD')) INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' LEFT OUTER JOIN DIM_PARTY ON STG_MITIGANTS.V_ISSUER_CODE = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN COALESCE(DIM_PARTY.D_RECORD_START_DATE, to_date('20260331','YYYYMMDD')) AND COALESCE(DIM_PARTY.D_RECORD_END_DATE, to_date('20260331','YYYYMMDD')) INNER JOIN DIM_PARTY_TYPE ON DIM_PARTY.V_PARTY_TYPE = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN COALESCE(DIM_PARTY_TYPE.D_RECORD_START_DATE, to_date('20260331','YYYYMMDD')) AND COALESCE(DIM_PARTY_TYPE.D_RECORD_END_DATE, to_date('20260331','YYYYMMDD')) LEFT OUTER JOIN DIM_ISSUE ON STG_MITIGANTS.V_INSTRUMENT_CODE = DIM_ISSUE.V_ISSUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN COALESCE(DIM_ISSUE.D_RECORD_START_DATE, to_date('20260331','YYYYMMDD')) AND COALESCE(DIM_ISSUE.D_RECORD_END_DATE, to_date('20260331','YYYYMMDD')) LEFT OUTER JOIN DIM_DATES A_DIM_DATES_MAT ON A_DIM_DATES_MAT.D_CALENDAR_DATE = STG_MITIGANTS.D_MATURITY_DATE LEFT OUTER JOIN FSI_MITIGANT_TYPE_RECLASS ON DIM_MITIGANT_TYPE.N_MITIGANT_TYPE_SKEY = FSI_MITIGANT_TYPE_RECLASS.N_MITIGANT_TYPE_SKEY AND FSI_MITIGANT_TYPE_RECLASS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' LEFT OUTER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' LEFT OUTER JOIN FSI_RUN_PARAMETER ON FSI_RUN_PARAMETER.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = FSI_RUN_PARAMETER.N_RUN_PARAMETER_SKEY INNER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'MITIGANT' WHERE 1=1 AND COALESCE(STG_MITIGANTS.f_cva_hedge, 'N') = 'Y' LOG ERRORS INTO FSI_CAP_MITIGANTS$ ('1776770652672_45227488_20260331_1_JOB_16306671578645') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
/
